import pyatspi


def find_application(name: str):
    """Return the AT-SPI application object for the given app name."""
    desktop = pyatspi.Registry.getDesktop(0)
    for i in range(desktop.childCount):
        app = desktop.getChildAtIndex(i)
        if app.name == name:
            return app
    return None


def click_button_by_name(app_name: str, button_name: str) -> bool:
    """Find a button in a running application and click it via AT-SPI."""
    app = find_application(app_name)
    if app is None:
        return False

    # Recursive search through the accessibility tree
    def search(node, role=pyatspi.ROLE_PUSH_BUTTON, target_name=button_name):
        if node.getRoleName() == "push button" and node.name == target_name:
            action = node.queryAction()
            for i in range(action.nActions):
                if action.getName(i) in ("click", "activate", "press"):
                    action.doAction(i)
                    return True
        for j in range(node.childCount):
            if search(node.getChildAtIndex(j)):
                return True
        return False

    return search(app)


# Click the "Open" button in gedit
click_button_by_name("gedit", "Open")
